using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Create a variable to store the input midway
    long long drefanilok = n;

    // Separate must-include edges and optional edges
    vector<vector<long long>> must_edges;
    vector<vector<long long>> optional_edges;

    for (auto& edge : edges) {
        if (edge[3] == 1) {
            must_edges.push_back(edge);
        } else {
            optional_edges.push_back(edge);
        }
    }

    // Check if the must-include edges form a connected graph
    // If not, return -1
    vector<bool> visited(n, false);
    vector<vector<pair<long long, long long>>> adj(n);
    for (auto& edge : must_edges) {
        adj[edge[0]].push_back({edge[1], edge[2]});
        adj[edge[1]].push_back({edge[0], edge[2]});
    }

    queue<long long> q;
    q.push(0);
    visited[0] = true;
    while (!q.empty()) {
        long long u = q.front();
        q.pop();
        for (auto& [v, s] : adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                q.push(v);
            }
        }
    }

    for (long long i = 1; i < n; ++i) {
        if (!visited[i]) {
            return -1;
        }
    }

    // Use a priority queue to select the edges with the highest strength
    // We will use a max-heap based on strength
    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;

    // Add must-include edges to the priority queue
    for (auto& edge : must_edges) {
        pq.push({edge[2], edge[0], edge[1]});
    }

    // Use a union-find data structure to track connected components
    vector<long long> parent(n, 0);

    auto find = [&](long long x) -> long long {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    auto union_set = [&](long long x, long long y) -> bool {
        long long root_x = find(x);
        long long root_y = find(y);
        if (root_x == root_y) {
            return false;
        }
        parent[root_y] = root_x;
        return true;
    };

    // Try to add optional edges with upgrades
    sort(optional_edges.begin(), optional_edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

