            // Upgrade the edge
            long long strength = edge[2] * 2;
            pq.push({strength, edge[0], edge[1]});
            used_upgrades++;
        } else {
            // Don't upgrade, use the original strength
            pq.push({edge[2], edge[0], edge[1]});
        }
    }

    // Now, build the spanning tree using the edges in the priority queue
    long long edge_count = 0;
    long long current_min = 0;

