        long long strength = pq.top().first;
        long long u = pq.top().second;
        long long v = pq.top().third;
        pq.pop();

        long long root_u = find(u);
        long long root_v = find(v);

        if (root_u != root_v) {
            union_set(root_u, root_v);
            edge_count++;
            current_min = min(current_min, strength);
            if (edge_count == n - 1) {
                break;
            }
        }
    }

    if (edge_count != n - 1) {
        return -1;
    }

    return current_min;
